// 갤러리 호출 인텐트 생성 및 실행
public void OpenAndroidGallery() {
android.content.Intent intent = new android.content.Intent(android.content.Intent.ACTION_PICK, android.provider.MediaStore.Images.Media.EXTERNAL_CONTENT_URI);
startActivityForResult(intent, 7777);
}

// C++에서 구현할 네이티브 함수 선언
public native void nativeOnImageSelected(String imagePath);

// URI 기반 이미지 바이트 스트림 변환 및 배열 반환
public byte[] GetImageData(String uriString) {
	try {
		android.net.Uri uri = android.net.Uri.parse(uriString);
		java.io.InputStream inputStream = getApplicationContext().getContentResolver().openInputStream(uri);
		java.io.ByteArrayOutputStream byteBuffer = new java.io.ByteArrayOutputStream();

		int bufferSize = 1024;
		byte[] buffer = new byte[bufferSize];
		int len = 0;

		while ((len = inputStream.read(buffer)) != -1) {
			byteBuffer.write(buffer, 0, len);
		}
		return byteBuffer.toByteArray();
	} catch (Exception e) {
		e.printStackTrace();
		return null;
	}
}

