if (requestCode == 7777 && resultCode == RESULT_OK && data != null) {
android.net.Uri selectedImage = data.getData();
if (selectedImage != null) {
// C++ 네이티브 함수로 선택된 이미지 URI 문자열 전달
nativeOnImageSelected(selectedImage.toString());
}
}
